import { useState } from "react";
import Navbar from "./components/Navbar";
import ProductCard from "./components/ProductCard";
import Cart from "./components/Cart";
import "./style.css";
import { Routes, Route } from "react-router-dom";
import ProductPage from "./components/ProductPage";

function App() {
  const [cart, setCart] = useState([]);
  const [search, setSearch] = useState("");
  const [showCart, setShowCart] = useState(false);

 const products = [
  { id: 1, name: "Rice", price: 50, img: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTCif5Oij8t-NEhOBkEKNYSOyUItL6TtqmKWw&s" },
  { id: 2, name: "Milk", price: 30, img: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRuz_5aV19nzwTbpqe4pbmCP4X0bAjis1MKgg&s" },
  { id: 3, name: "Apple", price: 80, img: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSRDQPjtXnFzP3gjABS8wPsMwb8tLatM1t0ng&s" },
  { id: 4, name: "Tomato", price: 40, img: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSeaU5rv9tqhSiPcNxQEdnXNlc4it7X0bF_tg&s" },
  { id: 5, name: "Potato", price: 25, img: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRsJkFU-sq14etfFycy3OonX1bEHL2nKZjMDQ&s" },
  { id: 6, name: "Onion", price: 35, img: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSwioLS1qIum_rKE5SeHCVQtVUNq_lZSPcYKA&s" },
  { id: 7, name: "Banana", price: 60, img: "data:image/jpeg;base64," },
  { id: 8, name: "Bread", price: 45, img: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSoVfpJjApDznOUqP28hDOPuuHt67Q2Qm2sUg&s" },
  { id: 9, name: "Eggs", price: 70, img: "data:image/jpeg;base64," },
  { id: 10, name: "Sugar", price: 55, img: "data:image/jpeg;base64," },
  { id: 11, name: "Salt", price: 20, img: "data:image/jpeg;base64," },
  { id: 12, name: "Oil", price: 120, img: "data:image/jpeg;base64," }
];
  const addToCart = (product) => {
    const existing = cart.find((item) => item.id === product.id);

    if (existing) {
      setCart(
        cart.map((item) =>
          item.id === product.id
            ? { ...item, qty: item.qty + 1 }
            : item
        )
      );
    } else {
      setCart([...cart, { ...product, qty: 1 }]);
    }
  };

  const filtered = products.filter((p) =>
    p.name.toLowerCase().includes(search.toLowerCase())
  );

  

return (
  <>
    <Navbar
      setSearch={setSearch}
      cartCount={cart.length}
      toggleCart={() => setShowCart(!showCart)}
    />

    {showCart && (
      <div className="overlay" onClick={() => setShowCart(false)}></div>
    )}

    <Routes>
      {/* Home Page */}
      <Route
        path="/"
        element={
          <div className="products">
            {filtered.map((p) => (
              <ProductCard
                key={p.id}
                product={p}
                addToCart={addToCart}
              />
            ))}
          </div>
        }
      />

      {/* Product Page */}
      <Route
        path="/product/:id"
        element={<ProductPage products={products} addToCart={addToCart} />}
      />
    </Routes>

    <Cart cart={cart} showCart={showCart} />
  </>
);}
export default App;